SELECT COUNT(asset_id) AS operational_assets_count
FROM asset_status
WHERE status = 'operational';

SELECT SUM(planned_capacity) AS total_planned_capacity
FROM capacity_planning
WHERE year = 2031;

SELECT DISTINCT primary_fuel_type
FROM assets
ORDER BY primary_fuel_type;

SELECT asset_id, last_updated
FROM asset_status
WHERE status = 'Operational';

SELECT SUM(planned_capacity) AS total_planned_capacity, AVG(planned_outage) AS average_planned_outage
FROM capacity_planning
WHERE year = 2031;
